interface.signature:
interface MinimalResult {
  repo_url: string;
  repo_org: string;
  repo_name: string;
  language: string;
  last_updated: string;
  similarity_score: number;
  github_link: string;
  metadata: { stars?: number; license?: string; };
}

interface SnippetResult extends MinimalResult {
  snippet: string;
  snippet_file_path: string;
  snippet_line_range: string;
  context_lines_before: number;
  context_lines_after: number;
  codespaces_link: string;
}

interface FullResult extends SnippetResult {
  gitingest_summary: string;
  full_file_context?: string;
  readme_excerpt?: string;
  repository_stats?: {
    contributors: number;
    commits_last_month: number;
    open_issues: number;
    last_commit: string;
  };
  dependencies?: Array<{
    name: string;
    version: string;
    type: 'runtime' | 'dev';
  }>;
}

